import java.util.Scanner;
import java.util.ArrayList;
import java.lang.Math;

public class Main {
    static class Point {
        double x, y;
        Point(double x, double y) {
            this.x = x;
            this.y = y;
        }
    }

    public static int orientation(Point p, Point q, Point r) {
        double val = (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
        if (Math.abs(val) < 1e-9) return 0; // Collinear
        return (val > 0) ? 1 : 2; // Clockwise or counterclockwise
    }

    public static void convexHull(ArrayList<Point> points, ArrayList<Point> hull) {
        int l = 0;
        for (int i = 1; i < points.size(); i++) {
            if (points.get(i).x < points.get(l).x) l = i;
        }

        int p = l, q;
        hull.clear();
        do {
            hull.add(points.get(p));
            q = (p + 1) % points.size();
            for (int i = 0; i < points.size(); i++) {
                if (orientation(points.get(p), points.get(i), points.get(q)) == 2) q = i;
            }
            p = q;
        } while (p != l);

        // Calculate the area of the convex hull
        double area = 0.0;
        for (int i = 0; i < hull.size(); i++) {
            int j = (i + 1) % hull.size();
            area += hull.get(i).x * hull.get(j).y;
            area -= hull.get(j).x * hull.get(i).y;
        }
        area = Math.abs(area) / 2.0;
        System.out.printf("%.1f\n", area);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            ArrayList<Point> points = new ArrayList<>();
            for (int i = 0; i < N; i++) {
                char op = sc.next().charAt(0);
                double x = sc.nextDouble();
                double y = sc.nextDouble();
                if (op == '+') {
                    points.add(new Point(x, y));
                } else {
                    // Remove point from the list
                    for (int j = 0; j < points.size(); j++) {
                        if (points.get(j).x == x && points.get(j).y == y) {
                            points.remove(j);
                            break;
                        }
                    }
                }
                ArrayList<Point> hull = new ArrayList<>();
                convexHull(points, hull);
            }
        }
    }
}

