    this.x = x;
    this.y = y;
}

function orientation(p, q, r) {
    let val = (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
    if (Math.abs(val) < 1e-9) return 0; // Collinear
    return val > 0 ? 1 : 2; // Clockwise or counterclockwise
}

function convexHull(points) {
    let l = 0;
    for (let i = 1; i < points.length; i++) {
        if (points[i].x < points[l].x) l = i;
    }

    let p = l, q;
    let hull = [];
    do {
        hull.push(points[p]);
        q = (p + 1) % points.length;
        for (let i = 0; i < points.length; i++) {
            if (orientation(points[p], points[i], points[q]) === 2) q = i;
        }
        p = q;
    } while (p !== l);

    // Calculate the area of the convex hull
    let area = 0.0;
    for (let i = 0; i < hull.length; i++) {
        let j = (i + 1) % hull.length;
        area += hull[i].x * hull[j].y;
        area -= hull[j].x * hull[i].y;
    }
    area = Math.abs(area) / 2.0;
    console.log(area.toFixed(1));
}

let T = parseInt(input[idx++]);
while (T-- > 0) {
    let N = parseInt(input[idx++]);
    let points = [];
    for (let i = 0; i < N; i++) {
        let [op, x, y] = input[idx++].split(' ');
        x = parseFloat(x);
        y = parseFloat(y);
        if (op === '+') {
            points.push(new Point(x, y));
        } else {
            // Remove point from the array
            points = points.filter(p => !(p.x === x && p.y === y));
        }
        convexHull(points);
    }
}

